records.model_output_text:
{
  "summary": "您已顺利完成腹腔镜胆囊切除术出院，回家后请重点关注伤口护理、按时服药和饮食调整，以促进恢复。",
  "medication": [
    "请按时服用出院带药：头孢克肟（预防感染）、布洛芬（按需止痛，勿空腹）、二甲双胍（控制血糖）。注意观察过敏反应（如皮疹）或胃肠道不适；如有不适及时联系医生。具体剂量请遵医嘱，不得自行停药或加减量。"
  ],
  "follow_up": [
    "术后1-2周到普外科或肝胆外科复诊，具体时间请向主管医生确认。请携带出院小结、化验单等相关资料。如出现发热、腹痛等异常情况，请提前就诊。"
  ],
  "wound_tube_care": [
    "腹部有4处小切口，敷料保持干燥。请勿自行撕掉敷料，术后7-10天拆线（具体时间请咨询医生）。观察伤口有无红肿、渗液或疼痛加剧。本次无引流管。"
  ],
  "diet_activity": [
    "饮食以清淡易消化为主，避免油腻食物，逐渐过渡到正常饮食；控制糖尿病饮食。多饮水。术后初期避免剧烈运动，可适当散步；不要提重物或做腹部用力的动作。"
  ],
  "warning_symptoms": [
    "如出现以下任一，请立即就医：发热（>38℃）、寒战、剧烈腹痛、腹胀、伤口红肿流脓、恶心呕吐、黄疸、心悸出汗（低血糖迹象）。"
  ],
  "home_care": [
    "保持居家环境清洁；监测体温、伤口情况和血糖（如有条件）；家属协助观察和提醒服药；戒烟戒酒；规律作息；注意药物安全储存。"
  ],
  "patient_friendly_expression": "回家后，记得按时吃药，不要吃太油腻的食物，注意伤口有没有发红或流脓。有不舒服及时联系医生。",
  "safety_notes": [
    "请严格遵医嘱执行所有医嘱；如有任何信息不明确，请向您的主管医生或护士确认；不要自行调整药物或治疗方案。"
  ]
}
